import { useEffect, useState, useContext } from "react";
import { AuthContext } from "./AuthContext";

export default function AdminUsers() {
    const { user } = useContext(AuthContext);
    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";

    const [users, setUsers] = useState([]);
    const [q, setQ] = useState("");
    const [loading, setLoading] = useState(true);
    const [err, setErr] = useState("");

    useEffect(() => {
        if (!isAdmin) return; // guard
        (async () => {
            try {
                setLoading(true);
                const res = await fetch("/api/users");
                if (!res.ok) throw new Error(`Failed to load users (${res.status})`);
                const data = await res.json();
                setUsers(Array.isArray(data) ? data : []);
                setErr("");
            } catch (e) {
                console.error(e);
                setErr(e.message || "Failed to load users");
            } finally {
                setLoading(false);
            }
        })();
    }, [isAdmin]);

    const filtered = users.filter(u => {
        const t = (q || "").toLowerCase();
        return (
            u.username?.toLowerCase().includes(t) ||
            u.email?.toLowerCase().includes(t) ||
            String(u.role || "").toLowerCase().includes(t)
        );
    });

    const removeById = async (id) => {
        if (!window.confirm("Delete this user?")) return;
        try {
            const res = await fetch(`/api/users/${id}`, { method: "DELETE" });
            if (!res.ok) {
                const body = await res.json().catch(() => ({}));
                throw new Error(body.message || `Delete failed (${res.status})`);
            }
            setUsers(prev => prev.filter(u => u.id !== id));
        } catch (e) {
            alert(e.message || "Delete failed");
        }
    };

    if (!isAdmin) {
        return (
            <div style={styles.wrap}>
                <h2>Users</h2>
                <p>You must be an admin to view this page.</p>
            </div>
        );
    }

    return (
        <div style={styles.wrap}>
            <div style={styles.headerRow}>
                <h2 style={{margin:0}}>Users</h2>
                <div>
                    <input
                        placeholder="Search username/email/role…"
                        value={q}
                        onChange={(e)=>setQ(e.target.value)}
                        style={styles.search}
                    />
                    <a href="#/" style={styles.backLink}>← Back</a>
                </div>
            </div>

            {loading && <p>Loading…</p>}
            {err && <p style={{color:"red"}}>{err}</p>}

            {!loading && !err && (
                <div style={styles.tableWrap}>
                    <div style={{...styles.row, ...styles.head}}>
                        <div style={{flex:1}}>ID</div>
                        <div style={{flex:2}}>Username</div>
                        <div style={{flex:3}}>Email</div>
                        <div style={{flex:1}}>Role</div>
                        <div style={{width:120}}>Actions</div>
                    </div>

                    {filtered.map(u => (
                        <div key={u.id} style={styles.row}>
                            <div style={{flex:1}}>{u.id}</div>
                            <div style={{flex:2}}>{u.username}</div>
                            <div style={{flex:3}}>{u.email}</div>
                            <div style={{flex:1}}>{u.role}</div>
                            <div style={{width:120}}>
                                <button onClick={()=>removeById(u.id)} style={styles.delBtn}>
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}

                    {filtered.length === 0 && (
                        <div style={{padding:"12px 8px"}}>No users found.</div>
                    )}
                </div>
            )}
        </div>
    );
}

const styles = {
    wrap: { padding: 20, maxWidth: 900, margin: "0 auto" },
    headerRow: { display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom: 12 },
    search: { padding: "6px 8px", border: "1px solid #ccc", borderRadius: 6, marginRight: 12 },
    backLink: { textDecoration: "none", border: "1px solid #ccc", padding: "6px 10px", borderRadius: 6, background: "#f8f8f8", color: "#333" },
    tableWrap: { background:"#fff", border:"1px solid #ddd", borderRadius: 8, overflow: "hidden" },
    row: { display:"flex", gap: 8, padding: "10px 8px", borderBottom:"1px solid #eee", alignItems:"center" },
    head: { background:"#f5f5f5", fontWeight: "bold" },
    delBtn: { padding:"6px 10px", background:"#b00020", color:"#fff", border:"none", borderRadius:6, cursor:"pointer" }
};
